VALUES
  ('optometrist-moex-00144', 'optometrist', 'optometrist-moex-114-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '根據遠距離及近距離隱斜位（distanceandnearphoria）量，考慮相同的隱斜位方向，下列何者為相反雙眼', '["內聚力不足（convergenceinsufficiency）與開散力過度（divergenceexcess）", "內聚力過度（convergenceexcess）與開散力不足（divergenceinsufficiency）", "內聚力不足與開散力不足", "內聚力過度與開散力過度  ⑤內聚力不足與基本內隱斜位（basicesophoria）  ⑥開散力不足與基本外隱斜 位（basicexophoria）  ⑦內聚力過度（convergenceexcess）與基本內隱斜位  ⑧開散力過度與基本外隱斜位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "99730c6ed7d9", "answer_pdf_sha1": "273f9b848536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00145', 'optometrist', 'optometrist-moex-114-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '固視偏差（fixationdisparity）測量稜鏡度時，下列那一項不是正確的相關結果？', '["調正稜鏡（alignprism）的度數，可以測量出固視的偏差", "調正稜鏡（alignprism）的度數即是受測者固視偏差的真正稜鏡度", "固視偏差稜鏡度數是斜位的代失償性（decompensated）表徵", "固視偏差的代償性，乃是因為閱讀工作時間太長，工作距離太近及燈光照明不恰當所造成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "99730c6ed7d9", "answer_pdf_sha1": "273f9b848536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
